// src/pages/Internship.jsx
import React, { useState, useEffect } from "react";
import InternshipModal from "../components/InternshipModal";
import { useAuth } from "../context/AuthContext";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Internship() {
  const [internships, setInternships] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [search, setSearch] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("");
  const [modalOpen, setModalOpen] = useState(false);
  const [editingInternship, setEditingInternship] = useState(null);

  const { currentUser } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    fetchInternships();
  }, []);

  useEffect(() => {
    handleFilter();
  }, [search, selectedCategory, internships]);

  const fetchInternships = async () => {
    try {
      const { data } = await axios.get("/api/internships");
      setInternships(data);
    } catch (err) {
      console.error("Error fetching internships:", err);
    }
  };

  const handleFilter = () => {
    let result = [...internships];
    if (search) {
      result = result.filter((item) =>
        item.title.toLowerCase().includes(search.toLowerCase())
      );
    }
    if (selectedCategory) {
      result = result.filter((item) => item.category === selectedCategory);
    }
    setFiltered(result);
  };

  const handleSave = async (formData) => {
    try {
      if (editingInternship) {
        await axios.put(`/api/internships/${editingInternship._id}`, formData);
      } else {
        await axios.post("/api/internships", formData);
      }
      fetchInternships();
    } catch (err) {
      console.error("Error saving internship:", err);
    }
  };

  const handleDelete = async (id) => {
    try {
      await axios.delete(`/api/internships/${id}`);
      fetchInternships();
    } catch (err) {
      console.error("Error deleting internship:", err);
    }
  };

  const handleApply = async (internshipId) => {
    try {
      await axios.post(`/api/applications/${internshipId}`, {}, {
        headers: { Authorization: `Bearer ${currentUser.token}` }
      });
      alert("Applied successfully!");
    } catch (err) {
      alert("Error applying: " + err.response?.data?.message || err.message);
    }
  };

  return (
    <div className="p-6">
      <div className="flex justify-between items-center flex-wrap gap-3 mb-4">
        <div className="flex gap-2">
          <input
            type="text"
            placeholder="Search title..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="border px-3 py-1 rounded"
          />
          <select
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
            className="border px-3 py-1 rounded"
          >
            <option value="">All Categories</option>
            {[...new Set(internships.map((i) => i.category))].map((cat) => (
              <option key={cat}>{cat}</option>
            ))}
          </select>
        </div>

        {(currentUser.role === "admin" || currentUser.role === "hr") && (
          <button
            onClick={() => setModalOpen(true)}
            className="bg-green-600 text-white px-4 py-2 rounded"
          >
            Post Internship
          </button>
        )}
      </div>

      {filtered.length === 0 ? (
        <p className="text-gray-500">No internships found.</p>
      ) : (
        <div className="grid md:grid-cols-2 gap-4">
          {filtered.map((intern) => (
            <div
              key={intern._id}
              className="border rounded-xl p-4 shadow-sm bg-white space-y-2"
            >
              <h2 className="text-lg font-bold">{intern.title}</h2>
              <p className="text-gray-600">{intern.company}</p>
              <p>{intern.category} | {intern.location} | {intern.mode}</p>
              <p className="text-sm text-gray-700">{intern.description}</p>

              <div className="flex flex-wrap gap-2 mt-2">
                {currentUser.role === "student" && (
                  <button
                    onClick={() => handleApply(intern._id)}
                    className="bg-blue-600 text-white px-3 py-1 rounded"
                  >
                    Apply
                  </button>
                )}
                {(currentUser.role === "admin" || currentUser.role === "hr") && (
                  <>
                    <button
                      onClick={() => {
                        setEditingInternship(intern);
                        setModalOpen(true);
                      }}
                      className="bg-yellow-500 text-white px-3 py-1 rounded"
                    >
                      Edit
                    </button>
                    <button
                      onClick={() => handleDelete(intern._id)}
                      className="bg-red-500 text-white px-3 py-1 rounded"
                    >
                      Delete
                    </button>
                  </>
                )}
                {currentUser.role === "admin" && (
                  <button
                    onClick={() => navigate(`/applications/${intern._id}`)}
                    className="bg-purple-600 text-white px-3 py-1 rounded"
                  >
                    View Applications
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      <InternshipModal
        isOpen={modalOpen}
        onClose={() => {
          setModalOpen(false);
          setEditingInternship(null);
        }}
        onSave={handleSave}
        editingInternship={editingInternship}
      />
    </div>
  );
}
